const fetch = require\('node-fetch'\);
const MLB_BASE = 'https://statsapi.mlb.com/api/v1';
async function run\(\) {
  // Career hitting
  const r = await fetch\(MLB_BASE + '/stats?stats=career&group=hitting&limit=5000&sportId=1'\);
  const d = await r.json\(\);
  const splits = d?.stats?.[0]?.splits ?? [];
  console.log\('Career hitting records:', splits.length\);
  // Check if Mike Trout is there
  const trout = splits.find\(s => s.player?.fullName?.toLowerCase\(\).includes\('trout'\)\);
  console.log\('Trout in career hitting:', trout ? trout.player.fullName + ' PA=' + trout.stat.plateAppearances : 'NOT FOUND'\);

  // Per-season leaders for ERA 2018 - does deGrom appear?
  const r2 = await fetch\(MLB_BASE + '/stats/leaders?leaderCategories=earnedRunAverage&season=2018&limit=100&sportId=1'\);
  const d2 = await r2.json\(\);
  const leaders = d2?.leagueLeaders?.[0]?.leaders ?? [];
  const dg = leaders.find\(l => l.person?.fullName?.toLowerCase\(\).includes\('degrom'\)\);
  console.log\('deGrom in 2018 ERA leaders:', dg ? { rank: dg.rank, era: dg.value } : 'NOT FOUND'\);
  console.log\('2018 ERA leader rank 1:', leaders[0]?.person?.fullName, leaders[0]?.value\);
  process.exit\(0\);
}
run\(\).catch\(e => { console.error\(e\); process.exit\(1\); }\);
